from collections import deque, defaultdict

class Graph:
    def __init__(self):
        self.adj_list = defaultdict(list)  # 邻接表表示

    def add_edge(self, u, v):
        self.adj_list[u].append(v)
        self.adj_list[v].append(u)  # 无向图

    def dfs(self, start):
        """深度优先搜索：递归实现"""
        visited = set()
        result = []

        def _dfs(vertex):
            visited.add(vertex)
            result.append(vertex)
            for neighbor in self.adj_list[vertex]:
                if neighbor not in visited:
                    _dfs(neighbor)

        _dfs(start)
        return result

    def bfs(self, start):
        """广度优先搜索：队列实现"""
        visited = {start}
        queue = deque([start])
        result = []

        while queue:
            vertex = queue.popleft()
            result.append(vertex)
            for neighbor in self.adj_list[vertex]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)

        return result

# 使用示例
g = Graph()
for u, v in [(0,1), (0,2), (1,3), (2,4)]:
    g.add_edge(u, v)

print(g.dfs(0))  # [0, 1, 3, 2, 4] 或类似（取决于插入顺序）
print(g.bfs(0))  # [0, 1, 2, 3, 4] 或类似
